  ('aboriginal-6f0ba476-moex-00752', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設社會上只有A、B兩人，且社會福利函數如圖所示。其中，U 與U 分別代表A、B兩人的 A B 效用，而社會福利水準SW ＞SW ＞SW ；此社會福利函數為下列何種形式？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
