  ('aboriginal-6f0ba476-moex-00754', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '公共財的消費不具敵對性是指：', '["不付費的消費者不能消費公共財", "多1人消費公共財所帶來的邊際成本等於零", "無法排除不付費的消費者消費公共財", "政府必須強制人民消費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "3ba507dcfc57", "answer_pdf_sha1": "da214f948881", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
